import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";
import { syncedStateRoutes, SyncedStateServer } from "rwsdk/use-synced-state/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { ChatRoom } from "@/app/components/ChatRoom";

export type AppContext = {};

export { SyncedStateServer };

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  ...syncedStateRoutes((env) => env.SYNCED_STATE_SERVER),
  render(Document, [
    route("/", Home),
    route("/chat/:roomId", ({ params }) => {
      const roomId = params.roomId;
      return (
        <div>
          <h1>Room: {roomId}</h1>
          <ChatRoom roomId={roomId} />
        </div>
      );
    }),
  ]),
]);

"use client";

import { useSyncedState } from "rwsdk/use-synced-state/client";
import { useState } from "react";

export function ChatRoom({ roomId }: { roomId: string }) {
  const [messages, setMessages] = useSyncedState<string[]>([], "messages", roomId);
  const [inputValue, setInputValue] = useState("");

  const handleSend = () => {
    const trimmed = inputValue.trim();
    if (trimmed === "") return;
    setMessages([...messages, trimmed]);
    setInputValue("");
  };

  const handleClear = () => {
    setMessages([]);
  };

  return (
    <div>
      <div style={{ maxHeight: "300px", overflowY: "auto", border: "1px solid #ccc", padding: "8px", marginBottom: "8px" }}>
        {messages.map((msg, i) => (
          <div key={i} data-testid="chat-message">
            {msg}
          </div>
        ))}
      </div>
      <input
        data-testid="chat-input"
        type="text"
        value={inputValue}
        onChange={(e) => setInputValue(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") handleSend();
        }}
      />
      <button data-testid="send-btn" onClick={handleSend}>
        Send
      </button>
      <button data-testid="clear-btn" onClick={handleClear}>
        Clear
      </button>
    </div>
  );
}

